class Solution:
    def constructDistancedSequence(self, n):
        length = 2 * n - 1
        best = [None]

        def backtrack(idx, res, used):
            if best[0] is not None and res[:idx] < best[0][:idx]:
                return
            if idx == length:
                if best[0] is None or res > best[0]:
                    best[0] = res[:]
                return
            if res[idx] != 0:
                backtrack(idx + 1, res, used)
                return
            for v in range(n, 0, -1):
                if used[v]:
                    continue
                if v == 1:
                    res[idx] = 1
                    used[1] = True
                    backtrack(idx + 1, res, used)
                    res[idx] = 0
                    used[1] = False
                else:
                    j = idx + v
                    if j < length and res[j] == 0:
                        res[idx] = v
                        res[j] = v
                        used[v] = True
                        backtrack(idx + 1, res, used)
                        res[idx] = 0
                        res[j] = 0
                        used[v] = False

        backtrack(0, [0] * length, [False] * (n + 1))
        return best[0]

