var constructDistancedSequence = function(n) {
    const length = 2 * n - 1;
    const res = new Array(length).fill(0);
    const used = new Array(n + 1).fill(false);

    function backtrack(idx) {
        if (idx === length) return true;
        if (res[idx] !== 0) return backtrack(idx + 1);
        for (let v = n; v >= 1; v--) {
            if (used[v]) continue;
            if (v === 1) {
                res[idx] = 1;
                used[1] = true;
                if (backtrack(idx + 1)) return true;
                res[idx] = 0;
                used[1] = false;
            } else {
                const j = idx + v;
                if (j < length && res[j] === 0) {
                    res[idx] = v;
                    res[j] = v;
                    used[v] = true;
                    if (backtrack(idx + 1)) return true;
                    res[idx] = 0;
                    res[j] = 0;
                    used[v] = false;
                }
            }
        }
        return false;
    }

    backtrack(0);
    return res;
};
